import random


def sort_in_place(items):
    # BUG: list.sort() returns None — caller treats return as list
    return items.sort()


def process(data):
    items = list(data)
    sorted_list = sort_in_place(items)
    # NoneType here, we intended reverse on sorted list
    return sorted_list.reverse()


def main():
    random.seed(0)
    data = [random.randint(1, 100) for _ in range(10)]
    result = process(data)
    print('result:', result)


if __name__ == '__main__':
    main()
